const source = items[0]?.json ?? {};

function parseJsonField(name, fallback) {
  if (source[name] === undefined || source[name] === null || source[name] === '') return fallback;
  if (typeof source[name] !== 'string') return source[name];
  try {
    return JSON.parse(source[name]);
  } catch (error) {
    throw new Error(`${name} must be valid JSON: ${error.message}`);
  }
}

const tickets = parseJsonField('tickets_json', []);
const config = parseJsonField('run_config_json', {});
const simulateSourceStatus = parseJsonField('simulate_source_status', {});

if (!Array.isArray(tickets)) {
  throw new Error('tickets_json must parse to an array');
}

const lookbackHours = Number(config.lookback_hours ?? 24);
const maxTicketsForLlm = Number(config.max_tickets_for_llm ?? 25);
if (!Number.isFinite(lookbackHours) || lookbackHours <= 0) {
  throw new Error('lookback_hours must be a positive number');
}
if (!Number.isInteger(maxTicketsForLlm) || maxTicketsForLlm < 1 || maxTicketsForLlm > 100) {
  throw new Error('max_tickets_for_llm must be an integer between 1 and 100');
}

const generatedAt = new Date().toISOString();
const runDate = generatedAt.slice(0, 10);
const runId = `support-digest-${runDate}-${Date.now()}`;

return [{
  json: {
    raw_ticket_source: tickets,
    run_config: {
      digest_frequency: config.digest_frequency || 'daily',
      lookback_hours: lookbackHours,
      max_tickets_for_llm: maxTicketsForLlm,
      delivery_channel: config.delivery_channel || 'customer-support-digest',
      include_low_priority: config.include_low_priority ?? true,
      use_llm: config.use_llm ?? true,
      llm_alias: config.llm_alias || 'general',
      risk_words: Array.isArray(config.risk_words) ? config.risk_words : [],
    },
    simulate_source_status: simulateSourceStatus,
    control: {
      run_id: runId,
      run_date: runDate,
      generated_at: generatedAt,
      idempotency_key: `customer-support-digest:${runDate}:${config.digest_frequency || 'daily'}`,
      retry_policy: {
        max_attempts: 3,
        timeout_ms: 120000,
        backoff: 'exponential',
        retry_on: ['429', '408', '5xx', 'network_timeout'],
      },
      llm_data_policy: {
        send_minimised_ticket_fields: true,
        redact_email_addresses: true,
        redact_phone_numbers: true,
        include_full_transcripts: false,
        llm_role: 'wording_and_theme_summary_not_source_of_truth',
      },
    },
  },
}];

const source = items[0]?.json ?? {};
const startedAt = new Date().toISOString();
const requestedStatus = source.simulate_source_status?.helpdesk || 'success';

try {
  if (requestedStatus === 'failed') {
    throw new Error('Simulated helpdesk API outage');
  }

  const tickets = requestedStatus === 'empty' ? [] : (source.raw_ticket_source || []);
  const status = requestedStatus === 'partial' ? 'partial' : (tickets.length ? 'success' : 'empty');
  const warnings = [];
  if (status === 'partial') warnings.push('Helpdesk source returned partial results; pagination or rate limit handling should be checked.');
  if (status === 'empty') warnings.push('Helpdesk source returned no tickets for the configured lookback window.');

  return [{
    json: {
      ...source,
      helpdesk_tickets_raw: tickets,
      source_statuses: {
        helpdesk: {
          source: 'helpdesk',
          status,
          checked_at: startedAt,
          completed_at: new Date().toISOString(),
          source_timestamp: tickets.map(t => t.updated_at || t.created_at).sort().pop() || null,
          records_returned: tickets.length,
          retry_policy: source.control?.retry_policy,
          warnings,
        },
      },
    },
  }];
} catch (error) {
  return [{
    json: {
      ...source,
      helpdesk_tickets_raw: [],
      source_statuses: {
        helpdesk: {
          source: 'helpdesk',
          status: 'failed',
          checked_at: startedAt,
          completed_at: new Date().toISOString(),
          source_timestamp: null,
          records_returned: 0,
          retry_policy: source.control?.retry_policy,
          warnings: ['Helpdesk source failed; digest will continue with an operations alert and no ticket data.'],
          error: error.message,
        },
      },
    },
  }];
}

const source = items[0]?.json ?? {};
const tickets = Array.isArray(source.helpdesk_tickets_raw) ? source.helpdesk_tickets_raw : [];
const config = source.run_config ?? {};
const riskWords = (config.risk_words || []).map(w => String(w).toLowerCase());

function redact(text) {
  return String(text || '')
    .replace(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi, '[redacted-email]')
    .replace(/\+?\d[\d\s().-]{7,}\d/g, '[redacted-phone]')
    .trim();
}

function classifyTheme(ticket) {
  const text = `${ticket.subject || ''} ${(ticket.tags || []).join(' ')} ${ticket.body || ''}`.toLowerCase();
  if (text.includes('login') || text.includes('sso') || text.includes('auth')) return 'authentication';
  if (text.includes('bug') || text.includes('fails') || text.includes('failing') || text.includes('error')) return 'bug';
  if (text.includes('feature') || text.includes('request') || text.includes('export')) return 'feature_request';
  if (text.includes('billing') || text.includes('invoice') || text.includes('payment')) return 'billing';
  if (text.includes('onboarding') || text.includes('invite') || text.includes('setup')) return 'onboarding';
  return 'general_support';
}

const dropped = [];
const normalised = [];

for (const ticket of tickets) {
  const tags = Array.isArray(ticket.tags) ? ticket.tags.map(t => String(t).toLowerCase()) : [];
  const subject = String(ticket.subject || '').trim();
  const body = String(ticket.body || '').trim();

  if (tags.includes('spam') || /cheap seo|buy traffic|crypto offer/i.test(`${subject} ${body}`)) {
    dropped.push({ id: ticket.id, reason: 'spam_or_low_signal' });
    continue;
  }

  if (!subject && !body) {
    dropped.push({ id: ticket.id, reason: 'missing_subject_and_body' });
    continue;
  }

  const priority = String(ticket.priority || 'normal').toLowerCase();
  if (!config.include_low_priority && priority === 'low') {
    dropped.push({ id: ticket.id, reason: 'low_priority_excluded' });
    continue;
  }

  const redactedBody = redact(body).slice(0, 600);
  const combined = `${subject} ${redactedBody}`.toLowerCase();
  const matchedRiskWords = riskWords.filter(word => combined.includes(word));
  const severity = priority === 'urgent' || priority === 'high' || matchedRiskWords.length > 0 ? 'high' : priority === 'low' ? 'low' : 'normal';

  normalised.push({
    id: String(ticket.id),
    subject: redact(subject).slice(0, 180),
    body_excerpt: redactedBody,
    status: ticket.status || 'unknown',
    priority,
    severity,
    theme: classifyTheme(ticket),
    tags,
    customer: ticket.customer || 'Unknown customer',
    plan: ticket.plan || 'Unknown plan',
    created_at: ticket.created_at || null,
    updated_at: ticket.updated_at || null,
    matched_risk_words: matchedRiskWords,
  });
}

const themeCounts = {};
const severityCounts = { high: 0, normal: 0, low: 0 };
for (const ticket of normalised) {
  themeCounts[ticket.theme] = (themeCounts[ticket.theme] || 0) + 1;
  severityCounts[ticket.severity] = (severityCounts[ticket.severity] || 0) + 1;
}

const sourceWarnings = Object.values(source.source_statuses || {})
  .flatMap(status => status.warnings || []);

return [{
  json: {
    ...source,
    normalised_tickets: normalised,
    dropped_tickets: dropped,
    ticket_summary: {
      raw_count: tickets.length,
      included_count: normalised.length,
      dropped_count: dropped.length,
      theme_counts: themeCounts,
      severity_counts: severityCounts,
      high_severity_count: severityCounts.high,
    },
    data_quality: {
      status: normalised.length ? 'usable' : 'no_usable_tickets',
      source_warnings: sourceWarnings,
      dropped_tickets: dropped,
    },
  },
}];

const source = items[0]?.json ?? {};
const alerts = [];

for (const [key, status] of Object.entries(source.source_statuses || {})) {
  if (['failed', 'partial', 'empty'].includes(status.status)) {
    alerts.push({
      alert_type: 'support_digest_source_warning',
      source: key,
      status: status.status,
      checked_at: status.checked_at,
      source_timestamp: status.source_timestamp,
      records_returned: status.records_returned,
      message: status.error || (status.warnings || []).join(' '),
      recommended_action: status.status === 'failed'
        ? 'Check helpdesk credentials, API availability, pagination and rate limits.'
        : 'Check whether the source response is expected for the current lookback window.',
    });
  }
}

return [{
  json: {
    ...source,
    operations_alerts: alerts,
  },
}];

const source = items[0]?.json ?? {};
const config = source.run_config ?? {};
const limit = config.max_tickets_for_llm ?? 25;
const ticketsForPrompt = (source.normalised_tickets || []).slice(0, limit).map(ticket => ({
  id: ticket.id,
  subject: ticket.subject,
  body_excerpt: ticket.body_excerpt,
  status: ticket.status,
  priority: ticket.priority,
  severity: ticket.severity,
  theme: ticket.theme,
  tags: ticket.tags,
  customer: ticket.customer,
  plan: ticket.plan,
}));

const prompt = `
You are a customer support operations analyst producing a concise ${config.digest_frequency || 'daily'} support digest for founders, customer success leaders, product managers and engineering leads.

Use the ticket data below to produce Markdown with this exact structure:

# Customer Support Digest - ${source.control?.run_date}

## Summary
- Give 3-5 bullets covering total ticket volume, high-severity volume, major themes, and customer impact.

## Top themes
List the top 3-5 themes. Include counts and concise supporting detail.

## High-severity items
List urgent or high-severity items needing immediate follow-up. Include suggested next step.

## Product / engineering signals
Summarise bugs, UX friction and feature requests that should be reviewed by product or engineering.

## Ticket list
List included tickets in compact form: #ID customer — subject (priority/severity).

Rules:
- Return only the final Markdown digest, no commentary.
- Do not invent ticket IDs or customers.
- Use account-level summaries rather than raw transcript detail.
- Treat the rule-based ticket metadata as the source of truth.
- The LLM is used for wording and theme synthesis, not as the authority for severity or operational status.

Source status:
${JSON.stringify(source.source_statuses || {}, null, 2)}

Ticket summary:
${JSON.stringify(source.ticket_summary || {}, null, 2)}

Tickets:
${JSON.stringify(ticketsForPrompt, null, 2)}
`.trim();

return [{
  json: {
    ...source,
    prompt,
    llm_prompt_ticket_count: ticketsForPrompt.length,
  },
}];

const source = items[0]?.json ?? {};
function firstString(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) return value.trim();
  }
  return '';
}
let content = firstString(
  source.response,
  source.digest_markdown,
  source.content,
  source.text,
  source.output,
  source.generated_text,
  source.message?.content,
  source.choices?.[0]?.message?.content,
  source.choices?.[0]?.text,
  source.results?.[0]?.text,
  source.data?.response,
  source.data?.content,
  source.data?.text,
  source.data?.output,
  source.data?.choices?.[0]?.message?.content,
  source.data?.choices?.[0]?.text
);
if (!content && Array.isArray(source.output)) {
  content = source.output.map(part => typeof part === 'string' ? part : part?.content || part?.text || '').filter(Boolean).join('\n').trim();
}
if (!content) {
  const availableKeys = Object.keys(source).sort().join(', ');
  throw new Error(`LLM response did not contain an expected digest field. Available top-level fields: ${availableKeys}`);
}
return [{
  json: {
    ...source,
    digest_markdown: content,
    digest_generation_mode: 'llm',
  },
}];

const source = items[0]?.json ?? {};
const error = source.error ?? source;
const message = error.message || error.description || source.message || 'Unknown LLM failure';
const failedAt = new Date().toISOString();

return [{
  json: {
    ...source,
    llm_alert: {
      alert_type: 'support_digest_llm_failure',
      failed_at: failedAt,
      message,
      recommended_action: 'Check local LLM availability, endpoint URL, request body shape and response extraction mapping.',
    },
  },
}];

const source = items[0]?.json ?? {};
const tickets = source.normalised_tickets || [];
const summary = source.ticket_summary || {};
const themeCounts = summary.theme_counts || {};
const sortedThemes = Object.entries(themeCounts).sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]));
const highSeverity = tickets.filter(t => t.severity === 'high');

const lines = [];
lines.push(`# Customer Support Digest - ${source.control?.run_date || new Date().toISOString().slice(0, 10)}`);
lines.push('');
lines.push('## Summary');
lines.push(`- ${summary.included_count || 0} usable tickets included from ${summary.raw_count || 0} raw tickets.`);
lines.push(`- ${summary.high_severity_count || 0} high-severity tickets identified by deterministic rules.`);
if (sortedThemes[0]) lines.push(`- Leading theme: ${sortedThemes[0][0]} (${sortedThemes[0][1]} tickets).`);
if (source.operations_alerts?.length) lines.push(`- Source warning: ${source.operations_alerts.length} operations alert(s) prepared.`);
if (source.llm_alert) lines.push('- LLM unavailable or response extraction failed; this fallback digest was generated deterministically.');
lines.push('');
lines.push('## Top themes');
if (sortedThemes.length) {
  sortedThemes.slice(0, 5).forEach(([theme, count], index) => lines.push(`${index + 1}. **${theme}** (${count} tickets)`));
} else {
  lines.push('- No themes available.');
}
lines.push('');
lines.push('## High-severity items');
if (highSeverity.length) {
  for (const ticket of highSeverity.slice(0, 10)) {
    lines.push(`- **#${ticket.id} ${ticket.customer} — ${ticket.subject}**`);
    lines.push(`  - Suggested next step: review owner, impact and customer communication plan.`);
  }
} else {
  lines.push('- No high-severity tickets identified.');
}
lines.push('');
lines.push('## Product / engineering signals');
const productSignals = tickets.filter(t => ['bug', 'authentication', 'feature_request'].includes(t.theme));
if (productSignals.length) {
  for (const ticket of productSignals.slice(0, 8)) lines.push(`- #${ticket.id} ${ticket.theme}: ${ticket.subject}`);
} else {
  lines.push('- No product or engineering signals identified.');
}
lines.push('');
lines.push('## Ticket list');
for (const ticket of tickets.slice(0, 25)) lines.push(`- #${ticket.id} ${ticket.customer} — ${ticket.subject} (${ticket.priority}/${ticket.severity})`);
if (!tickets.length) lines.push('- No usable tickets for this run.');

return [{
  json: {
    ...source,
    digest_markdown: lines.join('\n'),
    digest_generation_mode: 'deterministic_fallback',
  },
}];

const source = items[0]?.json ?? {};
if (typeof source.digest_markdown !== 'string' || !source.digest_markdown.trim()) {
  throw new Error('Preview / Save Digest expected a non-empty digest_markdown field');
}
return [{
  json: {
    ...source,
    preview_markdown: source.digest_markdown,
    digest_ready_at: new Date().toISOString(),
    delivery_status: 'ready_for_leadership_notification',
  },
}];

const source = items[0]?.json ?? {};
const subject = `Customer Support Digest - ${source.control?.run_date || new Date().toISOString().slice(0, 10)}`;
return [{
  json: {
    ...source,
    leadership_notification: {
      idempotency_key: source.control?.idempotency_key,
      channel: source.run_config?.delivery_channel || 'customer-support-digest',
      subject,
      body_markdown: source.digest_markdown,
      delivery_targets: ['email_or_slack_placeholder'],
      status: 'prepared_replace_with_email_slack_or_teams_node',
    },
  },
}];

const source = items[0]?.json ?? {};
const auditRecord = {
  audit_type: 'customer_support_digest',
  audit_id: source.control?.run_id,
  logged_at: new Date().toISOString(),
  run_date: source.control?.run_date,
  digest_generation_mode: source.digest_generation_mode,
  source_statuses: source.source_statuses,
  operations_alerts: source.operations_alerts || [],
  llm_alert: source.llm_alert || null,
  ticket_summary: source.ticket_summary,
  dropped_tickets: source.dropped_tickets,
  digest_markdown: source.digest_markdown,
  notification: source.leadership_notification,
  llm_data_policy: source.control?.llm_data_policy,
};
return [{
  json: {
    ...source,
    audit_record: auditRecord,
    audit_status: 'ready_for_durable_store',
  },
}];
